import ast, subprocess, sys

REPO = "/home/polaris/wt/phase3ab3"

class DocstringStripper(ast.NodeTransformer):
    def _strip(self, node):
        self.generic_visit(node)
        body = node.body
        if body and isinstance(body[0], ast.Expr) and isinstance(getattr(body[0], 'value', None), ast.Constant) and isinstance(body[0].value.value, str):
            body = body[1:]
            if not body:
                body = [ast.Pass()]
            node.body = body
        return node
    visit_FunctionDef = _strip
    visit_AsyncFunctionDef = _strip
    visit_ClassDef = _strip
    def visit_Module(self, node):
        self.generic_visit(node)
        body = node.body
        if body and isinstance(body[0], ast.Expr) and isinstance(getattr(body[0], 'value', None), ast.Constant) and isinstance(body[0].value.value, str):
            node.body = body[1:]
        return node

def norm(src):
    tree = DocstringStripper().visit(ast.parse(src))
    ast.fix_missing_locations(tree)
    return ast.unparse(tree)

files = subprocess.check_output(["git","diff","--name-only","HEAD","--","src/"], text=True, cwd=REPO).split()
failures = []
for f in files:
    head = subprocess.check_output(["git","show",f"HEAD:{f}"], text=True, cwd=REPO)
    with open(f"{REPO}/{f}") as fh:
        cur = fh.read()
    try:
        if norm(cur) != norm(head):
            failures.append(f)
    except SyntaxError as e:
        failures.append(f"{f} (SyntaxError: {e})")

print(f"CHECKED {len(files)} files")
if failures:
    print("FAIL")
    for x in failures:
        print("  ", x)
else:
    print("PASS")
